   314→
   315→	var (
   316→		search  = path
   317→		child   *node         // Child node
   318→		n       int           // Param counter
   319→		nk      kind          // Next kind
   320→		nn      *node         // Next node
   321→		ns      string        // Next search
   322→		pvalues = ctx.pvalues // Use the internal slice so the interface can keep the illusion of a dynamic slice
   323→	)
   324→
   325→	// Search order static > param > any
   326→	for {
   327→		if search == "" {
   328→			break
   329→		}
   330→
   331→		pl := 0 // Prefix length
   332→		l := 0  // LCP length
   333→
   334→		if cn.label != ':' {
   335→			sl := len(search)
   336→			pl = len(cn.prefix)
   337→
   338→			// LCP
   339→			max := pl
   340→			if sl < max {
   341→				max = sl
   342→			}
   343→			for ; l < max && search[l] == cn.prefix[l]; l++ {
   344→			}
   345→		}
   346→
   347→		if l == pl {
   348→			// Continue search
   349→			search = search[l:]
   350→			// Finish routing if no remaining search and we are on an leaf node
   351→			if search == "" && (nn == nil || cn.parent == nil || cn.ppath != "") {
   352→				break
   353→			}
   354→		}
   355→
   356→		// Attempt to go back up the tree on no matching prefix or no remaining search
   357→		if l != pl || search == "" {
   358→			if nn == nil { // Issue #1348
   359→				return // Not found
   360→			}
   361→			cn = nn
   362→			search = ns
   363→			if nk == pkind {
   364→				goto Param
   365→			} else if nk == akind {
   366→				goto Any
   367→			}
   368→		}
   369→
   370→		// Static node
   371→		if child = cn.findChild(search[0], skind); child != nil {
   372→			// Save next
   373→			if cn.prefix[len(cn.prefix)-1] == '/' { // Issue #623
   374→				nk = pkind
   375→				nn = cn
   376→				ns = search
   377→			}
   378→			cn = child
   379→			continue
   380→		}
   381→
   382→	Param:
   383→		// Param node
   384→		if child = cn.findChildByKind(pkind); child != nil {
   385→			// Issue #378
   386→			if len(pvalues) == n {
   387→				continue
   388→			}
   389→
   390→			// Save next
   391→			if cn.prefix[len(cn.prefix)-1] == '/' { // Issue #623
   392→				nk = akind
   393→				nn = cn
   394→				ns = search
   395→			}
   396→
   397→			cn = child
   398→			i, l := 0, len(search)
   399→			for ; i < l && search[i] != '/'; i++ {
   400→			}
   401→			pvalues[n] = search[:i]
   402→			n++
   403→			search = search[i:]
   404→			continue
   405→		}
   406→
   407→	Any:
   408→		// Any node
   409→		if cn = cn.findChildByKind(akind); cn != nil {
   410→			// If any node is found, use remaining path for pvalues
   411→			pvalues[len(cn.pnames)-1] = search
   412→			break
   413→		}
   414→
   415→		// No node found, continue at stored next node
   416→		// or find nearest "any" route
   417→		if nn != nil {
   418→			// No next node to go down in routing (issue #954)
   419→			// Find nearest "any" route going up the routing tree
   420→			search = ns
   421→			np := nn.parent
   422→			// Consider param route one level up only
   423→			if cn = nn.findChildByKind(pkind); cn != nil {
   424→				pos := strings.IndexByte(ns, '/')
   425→				if pos == -1 {
   426→					// If no slash is remaining in search string set param value
   427→					pvalues[len(cn.pnames)-1] = search
   428→					break
   429→				} else if pos > 0 {
   430→					// Otherwise continue route processing with restored next node
   431→					cn = nn
   432→					nn = nil
   433→					ns = ""
   434→					goto Param
   435→				}
   436→			}
   437→			// No param route found, try to resolve nearest any route
   438→			for {
   439→				np = nn.parent
   440→				if cn = nn.findChildByKind(akind); cn != nil {
   441→					break
   442→				}
   443→				if np == nil {
   444→					break // no further parent nodes in tree, abort
   445→				}
   446→				var str strings.Builder
   447→				str.WriteString(nn.prefix)
   448→				str.WriteString(search)
   449→				search = str.String()
   450→				nn = np
   451→			}
   452→			if cn != nil { // use the found "any" route and update path
   453→				pvalues[len(cn.pnames)-1] = search
   454→				break
   455→			}
   456→		}
   457→		return // Not found
   458→
   459→	}
   460→
   461→	ctx.handler = cn.findHandler(method)
   462→	ctx.path = cn.ppath
   463→	ctx.pnames = cn.pnames
   464→
   465→	// NOTE: Slow zone...
   466→	if ctx.handler == nil {
   467→		ctx.handler = cn.checkMethodNotAllowed()
   468→
   469→		// Dig further for any, might have an empty value for *, e.g.
   470→		// serving a directory. Issue #207.
   471→		if cn = cn.findChildByKind(akind); cn == nil {
   472→			return
   473→		}
   474→		if h := cn.findHandler(method); h != nil {
   475→			ctx.handler = h
   476→		} else {
   477→			ctx.handler = cn.checkMethodNotAllowed()
   478→		}
   479→		ctx.path = cn.ppath
   480→		ctx.pnames = cn.pnames
   481→		pvalues[len(cn.pnames)-1] = ""
   482→	}
   483→
   484→	return
   485→}
