package echo

import (
	"net/http"
	"testing"

	"github.com/stretchr/testify/assert"
)

// TestRouterTrailingSlashWildcard tests that trailing slash requests match wildcard routes
func TestRouterTrailingSlashWildcard(t *testing.T) {
	e := New()
	r := e.router

	// Routes as described in the issue
	r.Add(http.MethodGet, "/articles", func(Context) error {
		return nil
	})
	r.Add(http.MethodGet, "/articles/*", func(Context) error {
		return nil
	})

	c := e.NewContext(nil, nil).(*context)

	// Test 1: /articles should match /articles
	r.Find(http.MethodGet, "/articles", c)
	assert.NotNil(t, c.handler, "/articles should match")
	assert.Equal(t, "/articles", c.Path())

	// Reset context
	c = e.NewContext(nil, nil).(*context)

	// Test 2: /articles/ should match /articles/* (This is the failing case)
	r.Find(http.MethodGet, "/articles/", c)
	assert.NotNil(t, c.handler, "/articles/ should match /articles/*")
	assert.Equal(t, "/articles/*", c.Path())
	assert.Equal(t, "", c.Param("*"))

	// Reset context
	c = e.NewContext(nil, nil).(*context)

	// Test 3: /articles/whatever should match /articles/*
	r.Find(http.MethodGet, "/articles/whatever", c)
	assert.NotNil(t, c.handler, "/articles/whatever should match /articles/*")
	assert.Equal(t, "/articles/*", c.Path())
	assert.Equal(t, "whatever", c.Param("*"))
}

// Another test case for users
func TestRouterTrailingSlashWildcardUsers(t *testing.T) {
	e := New()
