	// Test: /users/ should match /users/*
	r.Find(http.MethodGet, "/users/", c)
	assert.NotNil(t, c.handler, "/users/ should match /users/*")
	assert.Equal(t, "/users/*", c.Path())
	assert.Equal(t, "", c.Param("*"))
}
EOF

