package main

import (
	"fmt"
	"net/http"
	"github.com/labstack/echo/v4"
)

func main() {
	e := echo.New()

	// Register routes as described in the issue
	e.GET("/articles", func(c echo.Context) error {
		return c.String(http.StatusOK, "articles")
	})
	e.GET("/articles/*", func(c echo.Context) error {
		return c.String(http.StatusOK, "articles-wildcard-"+c.Param("*"))
	})

	// Test the scenarios
	testCases := []struct {
		path     string
		expected string
	}{
		{"/articles", "articles"},
		{"/articles/", "articles-wildcard-"},
		{"/articles/whatever", "articles-wildcard-whatever"},
	}

	r := e.router
	for _, tc := range testCases {
		c := e.NewContext(nil, nil).(*echo.Context).(*echo.Context)
		r.Find(http.MethodGet, tc.path, c)
		if c.Handler() == nil {
			fmt.Printf("FAIL: %s - no handler found\n", tc.path)
		} else {
			fmt.Printf("PASS: %s - matched route: %s\n", tc.path, c.Path())
		}
	}
}
EOF
